114	/* This function is run by background process. It waits for a command,
115	 * runs it, and reports status back. It exits (in normal situations)
116	 * when the main process exits, because then a "read" on the pipe
117	 * will return 0, in which case "read_pipe" exits.
118	 */
119	static void background_system_process(void) {
120	  int len;
121	  int ret;
122	  char command[MAX_COMMAND+1];
123	
124	  while (1) {
125	    read_pipe(command_pipe_read, (char *)&len, sizeof(int));
126	    read_pipe(command_pipe_read, command, len);
127	    ret = system(command);
128	    write_pipe(result_pipe_write, (char *)&ret, sizeof(int));
129	  }
130	}
