133	/* background_system()                                              */
134	/*     return -1 on error, 0 on success                             */
135	/********************************************************************/
136	
137	int background_system(char *command) {
138	  int res;
139	  int len;
140	
141	  if (module_initialized == 0) {
142	    printf("FATAL: calling 'background_system' but 'start_background_system' was not called\n");
143	    abort();
144	  }
145	
146	  len = strlen(command)+1;
147	
148	  if (len > MAX_COMMAND) {
149	    printf("FATAL: command too long. Increase MAX_COMMAND (%d).\n", MAX_COMMAND);
150	    printf("command was: '%s'\n", command);
151	    abort();
152	  }
153	
154	  /* only one command can run at a time, so let's lock/unlock */
155	  lock_system();
156	  write_pipe(command_pipe_write, (char *)&len, sizeof(int));
157	  write_pipe(command_pipe_write, command, len);
158	  read_pipe(result_pipe_read, (char *)&res, sizeof(int));
159	  unlock_system();
160	
161	  if (res == -1 || !WIFEXITED(res) || WEXITSTATUS(res) != 0) return -1;
162	
163	  return 0;
164	}
